# Analyzes all auto-generated methods and outputs a CI-friendly JSON summary
$methodFiles = Get-ChildItem -Path "D:/lazy init ide/auto_generated_methods" -Include "*_AutoMethod.ps1","*_AutoFeature.ps1" -File -Recurse
$reportPathTxt = "D:/lazy init ide/auto_generated_methods/AutoGeneratedMethods_CIReport.txt"
$reportPathJson = "D:/lazy init ide/auto_generated_methods/AutoGeneratedMethods_CIReport.json"
$results = @()
foreach ($file in $methodFiles) {
    $lines = Get-Content $file.FullName -Raw
    $funcLine = ($lines -split "`n") | Where-Object { $_ -match '^function\s+' } | Select-Object -First 1
    $funcName = if ($funcLine) { ($funcLine -split '\s+')[1] } else { '(unknown)' }

    $hasTryCatch = ($lines -match 'try\s*{') -and ($lines -match 'catch\s*{')
    $hasStructuredLog = $lines -match 'Write-StructuredLog'

    $health = if ($hasTryCatch -and $hasStructuredLog) { 'healthy' } elseif ($hasTryCatch -or $hasStructuredLog) { 'partial' } else { 'needs-work' }

    $results += [pscustomobject]@{
        Method = $funcName
        File = $file.Name
        Health = $health
        HasTryCatch = $hasTryCatch
        HasStructuredLog = $hasStructuredLog
        CheckedAt = (Get-Date).ToString('o')
    }
}

$summary = [pscustomobject]@{
    Timestamp = (Get-Date).ToString('o')
    AutoMethodsDir = "D:/lazy init ide/auto_generated_methods"
    TotalMethods = $results.Count
    Healthy = ($results | Where-Object { $_.Health -eq 'healthy' }).Count -eq $results.Count
    Results = $results
}

$summary | ConvertTo-Json -Depth 5 | Set-Content $reportPathJson
$([string]::Join("`n", ($results | ForEach-Object { "[CI] $($_.Method) in $($_.File) -> $($_.Health)" })) ) | Set-Content $reportPathTxt
Write-Host "[CI] Analysis reports generated at $reportPathTxt and $reportPathJson"